dark.customCSS:
/* --- PROJECT SINGULARITY: VOID INTERFACE --- */
@keyframes phase-shift {
  0% { transform: translate(0); }
  20% { transform: translate(-1px, 1px); }
  40% { transform: translate(-1px, -1px); }
  60% { transform: translate(1px, 1px); }
  80% { transform: translate(1px, -1px); }
  100% { transform: translate(0); }
}

/* Cosmic Grain Texture */
body::after {
	content: '';
	position: fixed;
	top: 0; left: 0; width: 100%; height: 100%;
	opacity: 0.04;
	z-index: 9998;
	pointer-events: none;
	background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
}

/* Cherenkov Glow Prose */
.prose h1, .prose h2, .prose h3 {
	color: #00f2ff !important;
	text-shadow: 0 0 15px rgba(0, 242, 255, 0.4);
	text-transform: uppercase;
	letter-spacing: 2px;
}

/* Singularity Inputs */
input, textarea, .bg-gray-850 {
	background-color: rgba(2, 0, 13, 0.8) !important;
	border: 1px solid #330aff !important;
	border-radius: 0px !important;
	box-shadow: inset 0 0 20px rgba(51, 10, 255, 0.1);
	font-family: 'JetBrains Mono', monospace !important;
}

/* Kinetic Toggles (Buttons) */
button.bg-blue-500, button.bg-blue-600, .btn-primary {
	background: #00f2ff !important;
	color: #010005 !important;
	border-radius: 0px !important;
	font-weight: 900 !important;
	border: none !important;
	clip-path: polygon(10% 0, 100% 0, 90% 100%, 0% 100%);
	transition: all 0.2s;
}

button.bg-blue-500:hover {
	animation: phase-shift 0.2s infinite;
	background: #fff !important;
	box-shadow: 0 0 30px rgba(0, 242, 255, 0.6) !important;
}

/* Sidebar Void */
#sidebar {
	border-right: 1px solid rgba(51, 10, 255, 0.3) !important;
	background-color: rgba(1, 0, 5, 0.9) !important;
}

dark.canvasScript:
/**
 * Title: Gravitational Accretion
 * Description: High-speed particles orbiting the singularity (mouse).
 */

const CONFIG = {
    particleCount: 400,
    starColor: 'rgba(0, 242, 255, 0.5)',
    singularityColor: 'rgba(255, 255, 255, 0.8)',
    gravity: 0.05,
    friction: 0.96
};

let canvas, ctx, w, h;
let particles = [];
let mouse = { x: -5000, y: -5000 };

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    particles = [];
    for (let i = 0; i < CONFIG.particleCount; i++) {
        particles.push({
            x: Math.random() * w,
            y: Math.random() * h,
            vx: (Math.random() - 0.5) * 10,
            vy: (Math.random() - 0.5) * 10,
            size: Math.random() * 1.5 + 0.5
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    for (let p of particles) {
        let dx = mouse.x - p.x;
        let dy = mouse.y - p.y;
        let dist = Math.hypot(dx, dy);

        if (dist < 1000) {
            let force = (1000 - dist) / 1000;
            p.vx += (dx / dist) * force * CONFIG.gravity * 20;
            p.vy += (dy / dist) * force * CONFIG.gravity * 20;
        }

        p.x += p.vx;
        p.y += p.vy;
        p.vx *= CONFIG.friction;
        p.vy *= CONFIG.friction;

        // Draw Singularity Pull
        ctx.fillStyle = dist < 50 ? CONFIG.singularityColor : CONFIG.starColor;
        ctx.fillRect(p.x, p.y, p.size, p.size);

        if (p.x < 0 || p.x > w || p.y < 0 || p.y > h) {
            p.x = Math.random() * w;
            p.y = Math.random() * h;
            p.vx = 0; p.vy = 0;
        }
    }
    requestAnimationFrame(render);
}

